const e=JSON.parse('{"key":"v-28fdc088","path":"/%E5%90%8E%E7%AB%AF/java/8.html","title":"集合框架概念","lang":"zh-CN","frontmatter":{"title":"集合框架概念","icon":"edit","date":"2023-05-10T00:00:00.000Z","category":["Java"],"tag":["Java"],"star":true,"description":"集合框架 容器的概念 容器，就是可以容纳其他Java对象的对象。*Java Collections Framework(JCF)*为Java开发者提供了通用的容器，其始于JDK 1.2，优点是: 降低编程难度 提高程序性能 提高API间的互操作性 降低学习难度 降低设计和实现相关API的难度 增加程序的重用性 Java容器里只能放对象，对于基本类型(int, long, float, double等)，需要将其包装成对象类型后(Integer, Long, Float, Double等)才能放到容器里。很多时候拆包装和解包装能够自动完成。这虽然会导致额外的性能和空间开销，但简化了设计和编程。","head":[["meta",{"property":"og:url","content":"https://skym1.gitee.io/%E5%90%8E%E7%AB%AF/java/8.html"}],["meta",{"property":"og:site_name","content":"Skyme的博客"}],["meta",{"property":"og:title","content":"集合框架概念"}],["meta",{"property":"og:description","content":"集合框架 容器的概念 容器，就是可以容纳其他Java对象的对象。*Java Collections Framework(JCF)*为Java开发者提供了通用的容器，其始于JDK 1.2，优点是: 降低编程难度 提高程序性能 提高API间的互操作性 降低学习难度 降低设计和实现相关API的难度 增加程序的重用性 Java容器里只能放对象，对于基本类型(int, long, float, double等)，需要将其包装成对象类型后(Integer, Long, Float, Double等)才能放到容器里。很多时候拆包装和解包装能够自动完成。这虽然会导致额外的性能和空间开销，但简化了设计和编程。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-08-28T01:15:29.000Z"}],["meta",{"property":"article:author","content":"Skyme"}],["meta",{"property":"article:tag","content":"Java"}],["meta",{"property":"article:published_time","content":"2023-05-10T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-08-28T01:15:29.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"集合框架概念\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2023-05-10T00:00:00.000Z\\",\\"dateModified\\":\\"2023-08-28T01:15:29.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Skyme\\",\\"url\\":\\"https://skym1.gitee.io\\"}]}"]]},"headers":[{"level":2,"title":"容器的概念","slug":"容器的概念","link":"#容器的概念","children":[]},{"level":2,"title":"集合框架概念","slug":"集合框架概念","link":"#集合框架概念","children":[]},{"level":2,"title":"Collection","slug":"collection","link":"#collection","children":[{"level":3,"title":"Set","slug":"set","link":"#set","children":[]},{"level":3,"title":"List","slug":"list","link":"#list","children":[]},{"level":3,"title":"Queue","slug":"queue","link":"#queue","children":[]}]},{"level":2,"title":"Map","slug":"map","link":"#map","children":[{"level":3,"title":"TreeMap","slug":"treemap","link":"#treemap","children":[]},{"level":3,"title":"HashMap","slug":"hashmap","link":"#hashmap","children":[]},{"level":3,"title":"HashTable","slug":"hashtable","link":"#hashtable","children":[]},{"level":3,"title":"LinkedHashMap","slug":"linkedhashmap","link":"#linkedhashmap","children":[]}]}],"git":{"createdTime":1693185329000,"updatedTime":1693185329000,"contributors":[{"name":"Skym1","email":"412399240@qq.com","commits":1}]},"readingTime":{"minutes":2.39,"words":716},"filePathRelative":"后端/java/8.md","localizedDate":"2023年5月10日","excerpt":"<h1> 集合框架</h1>\\n<h2> 容器的概念</h2>\\n<p>容器，就是可以容纳其他Java对象的对象。*Java Collections Framework(JCF)*为Java开发者提供了通用的容器，其始于JDK 1.2，优点是:</p>\\n<ul>\\n<li>降低编程难度</li>\\n<li>提高程序性能</li>\\n<li>提高API间的互操作性</li>\\n<li>降低学习难度</li>\\n<li>降低设计和实现相关API的难度</li>\\n<li>增加程序的重用性</li>\\n</ul>\\n<p>Java容器里只能放对象，对于基本类型(int, long, float, double等)，需要将其包装成对象类型后(Integer, Long, Float, Double等)才能放到容器里。很多时候拆包装和解包装能够自动完成。这虽然会导致额外的性能和空间开销，但简化了设计和编程。</p>","autoDesc":true}');export{e as data};
